	for x in range(startSens, endSens):
		base_path='/'.join(tagPath.split('/')[:-2])
		base_list=[
		base_path + "/data/Val_PV" + str(items[x-1]) + ".Enabled", 
		base_path + "/data/Sts_PV" + str(items[x-1]) + "Reject.Enabled",
		base_path + "/data/Sts_PV" + str(items[x-1]) + "_Deviation.Enabled",
		base_path + "/data/Cfg_HasPV" + str(items[x-1]) + ".Enabled"
		]
		response=system.tag.writeAsync(base_list,[doEnable]*len(base_list))	

if initialChange:
